import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"诅咒之刃","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/诅咒之刃.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/诅咒之刃.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/诅咒之刃.md"};function l(_,a,i,p,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"诅咒之刃",tabindex:"-1"},[s("诅咒之刃 "),e("a",{class:"header-anchor",href:"#诅咒之刃","aria-label":'Permalink to "诅咒之刃"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004")])])],-1),o('<h1 id="诅咒之刃-1" tabindex="-1">诅咒之刃 <a class="header-anchor" href="#诅咒之刃-1" aria-label="Permalink to &quot;诅咒之刃&quot;">​</a></h1><p>诅咒之刃</p><p>A+4000<br> 魔幻本质<br> 由被疫病所感染孽物肿胀眼魔的身上发现，拥有可以斩断世间一切的锐利,是那罪恶满身的国王重获新生之后最喜爱的武器。<br> 它的剑身上满载神明对于王国的诅咒，以至于在王国之中除国王以外再无第二人敢将其举起，但国王却将诅咒视为祝福，他毫不犹豫用其斩碎了诸神的封碎，接受了恶魔的馈赠，或许于他而言，债多不压身。<br> 武器伤害：94L<br> 专业：剑<br> 类型:长剑<br> 体积：3<br> 特性：【12威猛】【法破】【8加骰】【湮灭】【暴虐之征】【不祥之力】【神之诅咒】<br> 这是一柄通体青黑，剑刃呈狭长棱形的奇异长剑，其质地坚硬无比，但持握在手中时的触感却如同握着一只满是血肉的残肢。剑刃的棱形缺口之中，镶嵌着一只通体漆黑邪异眼球，那本应是死物的眼球，却仿佛注视着所有人。<br> 暴虐之征：这把刀在漫长的时光中仿佛拥有自己的生命，想要使用它的力量就只能使用最为纯粹的暴力,你无法使用除力量以外的任何属性来使用它。<br> 不祥之力:锐利的剑刃在接触到皮肤的那一刻，与他接触的一切事物己然沾染上了它最根本的罪祸。剑锋所划过的地方，都将在那一刻成为这件事物最根本的弱点。你用这把剑进行的攻击检定具有【传奇】特性,并且造成的伤害将全部转化为韧性伤害。<br> 神之诅咒:此等孽物本就不因存在于世上，无法直接干涉世间的诸神便对这把剑留下了他们的诅咒，任何使用此剑的人都将因为各种理由而死于非命。当你在持用这把剑时受到任何来自除自身以外的伤害时，你的肉体将会立即崩坏你也将立即死去，在本场影片结束前不能复活。（该效果无法被类似将他人造成伤害转化为自身造成伤害的效果所影响）</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
